import React, { useEffect, useState } from 'react';
import axios from 'axios';

const statusColor = { pending: '#f39c12', approved: '#27ae60', rejected: '#e74c3c', expired: '#95a5a6' };

const s = {
  page: { padding: 32, maxWidth: 1000, margin: '0 auto' },
  title: { fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 20 },
  filters: { display: 'flex', gap: 10, marginBottom: 20 },
  filterBtn: { padding: '7px 18px', borderRadius: 20, border: '1.5px solid #ddd', cursor: 'pointer', fontWeight: 600, fontSize: 13 },
  table: { width: '100%', borderCollapse: 'collapse', background: '#fff', borderRadius: 12, overflow: 'hidden', boxShadow: '0 2px 12px rgba(0,0,0,0.07)' },
  th: { background: '#1a3a5c', color: '#fff', padding: '12px 14px', textAlign: 'left', fontSize: 13 },
  td: { padding: '12px 14px', borderBottom: '1px solid #f5f5f5', fontSize: 13 },
  badge: { padding: '3px 12px', borderRadius: 20, fontSize: 12, fontWeight: 700 },
  approveBtn: { padding: '5px 14px', background: '#27ae60', color: '#fff', border: 'none', borderRadius: 6, cursor: 'pointer', fontWeight: 600, marginRight: 6, fontSize: 12 },
  rejectBtn: { padding: '5px 14px', background: '#e74c3c', color: '#fff', border: 'none', borderRadius: 6, cursor: 'pointer', fontWeight: 600, fontSize: 12 },
};

export default function AdminPasses() {
  const [passes, setPasses] = useState([]);
  const [filter, setFilter] = useState('');
  const [loading, setLoading] = useState(false);

  const load = (status = '') => {
    setFilter(status);
    const url = status ? `/api/admin/passes?status=${status}` : '/api/admin/passes';
    axios.get(url).then(r => setPasses(r.data));
  };

  useEffect(() => load(), []);

  const approve = async (id) => {
    setLoading(true);
    await axios.put(`/api/admin/passes/${id}/approve`, {});
    load(filter); setLoading(false);
  };

  const reject = async (id) => {
    const reason = prompt('Rejection reason (optional):') || 'Not eligible';
    await axios.put(`/api/admin/passes/${id}/reject`, { remarks: reason });
    load(filter);
  };

  const statuses = ['', 'pending', 'approved', 'rejected', 'expired'];

  return (
    <div style={s.page}>
      <div style={s.title}>📋 Manage Bus Passes</div>
      <div style={s.filters}>
        {statuses.map(st => (
          <button key={st} style={{ ...s.filterBtn, background: filter === st ? '#1a3a5c' : '#fff', color: filter === st ? '#fff' : '#333' }} onClick={() => load(st)}>
            {st ? st.charAt(0).toUpperCase() + st.slice(1) : 'All'}
          </button>
        ))}
      </div>
      <table style={s.table}>
        <thead>
          <tr>
            <th style={s.th}>Student</th><th style={s.th}>USN</th><th style={s.th}>Route</th>
            <th style={s.th}>Type</th><th style={s.th}>Applied</th><th style={s.th}>Status</th><th style={s.th}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {passes.map(p => (
            <tr key={p._id}>
              <td style={s.td}><div style={{ fontWeight: 600 }}>{p.student?.name}</div><div style={{ color: '#888', fontSize: 12 }}>{p.student?.email}</div></td>
              <td style={s.td}>{p.usn}</td>
              <td style={s.td}>{p.from} → {p.to}</td>
              <td style={s.td}>{p.passType}</td>
              <td style={s.td}>{new Date(p.appliedAt).toLocaleDateString()}</td>
              <td style={s.td}><span style={{ ...s.badge, background: statusColor[p.status] + '22', color: statusColor[p.status] }}>{p.status}</span></td>
              <td style={s.td}>
                {p.status === 'pending' && (
                  <>
                    <button style={s.approveBtn} onClick={() => approve(p._id)} disabled={loading}>✓ Approve</button>
                    <button style={s.rejectBtn} onClick={() => reject(p._id)}>✗ Reject</button>
                  </>
                )}
                {p.status !== 'pending' && <span style={{ color: '#ccc', fontSize: 12 }}>—</span>}
              </td>
            </tr>
          ))}
          {passes.length === 0 && <tr><td colSpan={7} style={{ ...s.td, textAlign: 'center', color: '#aaa', padding: 30 }}>No passes found</td></tr>}
        </tbody>
      </table>
    </div>
  );
}
